def _operation_0_body_0_default_factory_facts(ctx, facade):
    from inspect import Parameter, signature
    fields = sorted((field for field in ctx.records(FieldsCollection) if field.field_owner == facade.class_id), key=lambda field: field.field_order)
    by_name = {field.field_name: field for field in fields}
    by_id = {field.field_id: field for field in fields}
    factory_fields = [field for field in fields if field.has_default_factory]
    graph = {field.field_id: set() for field in factory_fields}
    param_names_by_id = {}
    deps = []
    diagnostics = []

    def add_diagnostic(field, suffix, message):
        diagnostics.append(ComputedClassDiagnostic(diagnostic_id=f'{field.field_id}.{suffix}', diagnostic_owner=facade.class_id, diagnostic_field_id=field.field_id, diagnostic_message=message))
    for field in fields:
        if field.field_kind == 'initvar' and field.init == False and (field.has_default == False) and (field.has_default_factory == False):
            add_diagnostic(field, 'initvar', f'init-only field {field.field_name} with init=False must specify default or default_factory')
    for field in factory_fields:
        try:
            parameters = tuple(signature(field.default_factory).parameters.values())
        except (TypeError, ValueError) as exc:
            parameters = ()
            add_diagnostic(field, 'signature', f'field {field.field_name} default_factory cannot be inspected: {exc}')
        param_names_by_id[field.field_id] = tuple((parameter.name for parameter in parameters))
        for param_order, parameter in enumerate(parameters):
            if parameter.kind in (Parameter.POSITIONAL_ONLY, Parameter.VAR_POSITIONAL, Parameter.VAR_KEYWORD):
                add_diagnostic(field, parameter.name, f'field {field.field_name} default_factory has unsupported parameter {parameter.name!r}')
                continue
            provider = by_name.get(parameter.name)
            if provider is None:
                add_diagnostic(field, parameter.name, f'field {field.field_name} default_factory unknown dependency {parameter.name!r}')
                continue
            deps.append((field, provider, parameter.name, param_order))
            if provider.field_id in graph:
                graph[field.field_id].add(provider.field_id)
    field_order = {field.field_id: field.field_order for field in fields}
    visiting = set()
    visited = set()
    ordered_field_ids = []

    def visit(field_id, path):
        if field_id in visited:
            return
        if field_id in visiting:
            cycle = path[path.index(field_id):]
            names = ' -> '.join((f'{facade.class_name}.{by_id[item].field_name}' for item in cycle))
            add_diagnostic(by_id[field_id], 'cycle', f'default_factory dependency cycle: {names}')
            return
        visiting.add(field_id)
        for provider_id in sorted(graph.get(field_id, ()), key=lambda item: field_order[item]):
            visit(provider_id, [*path, provider_id])
        visiting.remove(field_id)
        visited.add(field_id)
        ordered_field_ids.append(field_id)
    for field in factory_fields:
        visit(field.field_id, [field.field_id])
    eval_order_by_id = {field_id: eval_order for eval_order, field_id in enumerate(ordered_field_ids)}
    for field in factory_fields:
        param_names = param_names_by_id[field.field_id]
        action_kind = 'zero_arg' if not param_names else 'parameterized'
        ctx.write(DefaultFactoryInitActionsCollection, DefaultFactoryInitAction(action_id=field.field_id, action_owner=facade.class_id, action_field_id=field.field_id, action_field_name=field.field_name, action_field_order=field.field_order, action_kind=action_kind, action_eval_order=eval_order_by_id[field.field_id], factory_param_names=param_names), policy=RejectDuplicate)
    for consumer, provider, param_name, param_order in deps:
        ctx.write(DefaultFactoryDepsCollection, DefaultFactoryDep(dependency_owner=facade.class_id, consumer_field_id=consumer.field_id, consumer_eval_order=eval_order_by_id[consumer.field_id], provider_field_id=provider.field_id, provider_name=provider.field_name, param_name=param_name, param_order=param_order), policy=RejectDuplicate)
    for eval_order, field_id in enumerate(ordered_field_ids):
        field = by_id[field_id]
        ctx.write(InitEvaluationStepsCollection, InitEvaluationStep(eval_step_id=field.field_id, eval_owner=facade.class_id, eval_field_id=field.field_id, eval_field_name=field.field_name, eval_order=eval_order), policy=RejectDuplicate)
    for diagnostic in diagnostics:
        ctx.write(DiagnosticsCollection, diagnostic, policy=ReplaceExisting)

def run_build_default_factory_facts(builder):
    ctx = DDSOperationContext(builder, 'BuildDefaultFactoryFacts', ordered_inputs={})
    for facade in ctx.records(FacadesCollection):
        try:
            _operation_0_body_0_default_factory_facts(ctx, facade)
        except AssemblyDiagnosticError:
            raise
        except Exception as exc:
            raise OperationExecutionError(f"operation 'BuildDefaultFactoryFacts' failed for facade={facade!r}") from exc

def run_raise_computed_class_diagnostics(builder):
    ctx = DDSOperationContext(builder, 'RaiseComputedClassDiagnostics', ordered_inputs={})
    for diagnostic in ctx.records(DiagnosticsCollection):
        raise AssemblyDiagnosticError(diagnostic.diagnostic_message)

def run_operations(builder):
    run_build_default_factory_facts(builder)
    run_raise_computed_class_diagnostics(builder)
    return builder

def build_container(builder):
    run_operations(builder)
    return builder.freeze()

